#include<bits/stdc++.h>
using namespace std;
#define int long long
int a[1000005],b[1000005];
signed main() {
	int n,m,k;
	cin>>n;
	for (int i=0;i<n;i++) {
		cin>>a[i];
	}
	cin>>m;
	for (int i=1;i<=m; i++) {
		cin>>k;
		b[i]=a[k];
		int ans=0;
		for (int j=1;j<=i;j++) {
			if (b[j]>b[i]) {
				swap(b[i],b[j]);
				ans++;
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
